     1→import {
     2→  createAgentUIStreamResponse,
     3→  createUIMessageStream,
     4→  createUIMessageStreamResponse,
     5→  TypeValidationError,
     6→  type UIMessage,
     7→  validateUIMessages,
     8→} from "ai";
     9→import type { NextRequest } from "next/server";
    10→import { after } from "next/server";
    11→import {
    12→  endActiveSpan,
    13→  extractLatestUserTextFromUiMessages,
    14→  extractTextFromUiMessage,
    15→  type MediaAgentCallOptions,
    16→  mediaAgent,
    17→  mediaAgentTools,
    18→  observe,
    19→  summarizeParts,
    20→  updateAgentObservation,
    21→  updateAgentTrace,
    22→} from "@/lib/agents";
    23→import { authenticateUser } from "@/lib/auth/utils";
    24→import { langfuseSpanProcessor } from "@/lib/otel/langfuse-processor";
    25→import {
    26→  createChat,
    27→  getChatById,
    28→} from "@/server/database/repo/postgress-repo-functions/chat.repo";
    29→import {
    30→  loadChatMessages,
    31→  saveChatMessage,
    32→} from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
    33→import { findProjectByIdForUser } from "@/server/database/repo/postgress-repo-functions/imageEditorProjects.repo";
    34→import logger from "@/utils/logger";
    35→
    36→// Allow streaming up to 180s
    37→export const maxDuration = 180;
    38→
    39→const handler = async (req: NextRequest) => {
    40→  const requestId = crypto.randomUUID();
    41→  const { id: userId } = await authenticateUser(requestId);
    42→
    43→  // Get the last message, projectId, and optionally chatId from client
    44→  const {
    45→    message,
    46→    id: projectId,
    47→    chatId: clientChatId,
    48→    globalSystemInstructions,
    49→    modelSelection,
    50→  }: {
    51→    message: UIMessage;
    52→    id: string;
    53→    chatId?: string;
    54→    globalSystemInstructions?: string;
    55→    modelSelection?: {
    56→      isAutoMode: boolean;
    57→      imageModel: string | null;
    58→      videoModel: string | null;
    59→    };
    60→  } = await req.json();
    61→
    62→  // Log model selection for debugging
    63→  logger.info(`Model selection received: ${JSON.stringify(modelSelection)}`);
    64→
    65→  const initialTraceInput =
    66→    extractTextFromUiMessage(message) ??
    67→    `[${message.role}] ${summarizeParts(message.parts as UIMessage["parts"])}`;
    68→
    69→  try {
    70→    // Verify project exists and user owns it
    71→    const project = await findProjectByIdForUser({ projectId, userId });
    72→    if (!project) {
    73→      logger.error("Project not found or access denied");
    74→      return new Response(
    75→        JSON.stringify({ error: "Project not found or access denied" }),
    76→        { status: 403, headers: { "Content-Type": "application/json" } },
    77→      );
    78→    }
    79→
    80→    // Resolve or create chat
    81→    // Client always sends a chatId (either existing or pre-generated UUID)
    82→    let chat: Awaited<ReturnType<typeof getChatById>> | null = null;
    83→    let previousMessages: UIMessage[] = [];
    84→
    85→    if (!clientChatId) {
    86→      // Chat not found with provided chatId - create a new chat
    87→      logger.error("No chatId provided by client", {
    88→        requestId,
    89→        userId,
    90→        projectId,
    91→      });
    92→      return new Response(
    93→        JSON.stringify({
    94→          error:
    95→            "chatId is required but was not provided. This usually indicates an outdated or misconfigured client. Please refresh the page or update the client and try again.",
    96→        }),
    97→        {
    98→          status: 400,
    99→          headers: { "Content-Type": "application/json" },
   100→        },
   101→      );
   102→    }
   103→
   104→    // Update Langfuse trace with context (now that we have a chat/session id)
   105→    updateAgentTrace({
   106→      name: "agent-chat-message",
   107→      sessionId: clientChatId,
   108→      userId,
   109→      input: initialTraceInput,
   110→      metadata: {
   111→        projectId,
   112→        requestId,
   113→        isManualMode: modelSelection ? !modelSelection.isAutoMode : false,
   114→      },
   115→    });
   116→
   117→    updateAgentObservation({
   118→      input: initialTraceInput,
   119→    });
   120→
   121→    // Try to get existing chat
   122→    chat = await getChatById({ chatId: clientChatId, userId });
   123→
   124→    if (chat) {
   125→      // Existing chat - load messages
   126→      previousMessages = await loadChatMessages(chat.id, userId);
   127→    } else {
   128→      // No chatId provided - create a new chat
   129→
   130→      chat = await createChat({
   131→        id: clientChatId, // Use client's pre-generated ID
   132→        projectId,
   133→        userId,
   134→        title: "New Chat",
   135→      });
   136→
   137→      if (!chat) {
   138→        logger.error("Failed to create chat");
   139→        return new Response(
   140→          JSON.stringify({ error: "Failed to create chat" }),
   141→          { status: 500, headers: { "Content-Type": "application/json" } },
   142→        );
   143→      }
   144→      // No previous messages for new chat
   145→      previousMessages = [];
   146→    }
   147→
   148→    // Track continuation message ID to maintain consistent IDs across multi-step tool execution
   149→    // When client sends an assistant message (via sendAutomaticallyWhen), we reuse its ID
   150→    // so all steps share the same message ID (like DB upsert pattern)
   151→    let continuationMessageId: string | undefined;
   152→
   153→    // Build messages array for LLM based on incoming message role
   154→    let messages: UIMessage[];
   155→
   156→    if (message.role === "user") {
   157→      // User message: append to conversation history
   158→      messages = [...previousMessages, message];
   159→      logger.info(`User message received, total messages: ${messages.length}`);
   160→    } else if (message.role === "assistant") {
   161→      // Assistant message sent by client's sendAutomaticallyWhen
   162→      // Preserve the client's message ID for consistency
   163→      continuationMessageId = message.id;
   164→      // Use only previous messages (new assistant message will be generated)
   165→      messages = previousMessages;
   166→      logger.info(
   167→        `Assistant message received (auto-continuation), using ${messages.length} previous messages, continuationId: ${continuationMessageId}`,
   168→      );
   169→    } else {
   170→      // Unexpected role (system, etc.)
   171→      logger.warn(`Unexpected message role: ${message.role}`);
   172→      messages = [...previousMessages, message];
   173→    }
   174→
   175→    const bestTraceInput =
   176→      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;
   177→
   178→    updateAgentObservation({ input: bestTraceInput });
   179→    updateAgentTrace({ input: bestTraceInput });
   180→
   181→    // Validate messages against tool schemas to ensure compatibility
   182→    let validatedMessages: UIMessage[];
   183→    try {
   184→      validatedMessages = await validateUIMessages({
   185→        messages,
   186→        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
   187→        tools: mediaAgentTools as any,
   188→      });
   189→    } catch (error) {
   190→      if (error instanceof TypeValidationError) {
   191→        // Log validation error for monitoring
   192→        logger.warn(
   193→          `Message validation failed, starting with only new message: ${error.message}`,
   194→        );
   195→        // If validation fails (e.g., old tool schemas), start fresh with just the new message
   196→        validatedMessages = [message];
   197→      } else {
   198→        throw error;
   199→      }
   200→    }
   201→
   202→    // Save user message to database immediately (before streaming)
   203→    // Assistant messages are saved in onFinish callback after streaming completes
   204→    if (message.role === "user") {
   205→      await saveChatMessage({ message, chatId: chat.id, userId });
   206→      logger.info(`User message saved: ${message.id}`);
   207→    }
   208→    // Build agent call options from request
   209→    const agentOptions: MediaAgentCallOptions = {
   210→      isAutoMode: modelSelection?.isAutoMode ?? true,
   211→      imageModel: modelSelection?.imageModel ?? null,
   212→      videoModel: modelSelection?.videoModel ?? null,
   213→      globalSystemInstructions: globalSystemInstructions?.trim(),
   214→    };
   215→
   216→    // Flush Langfuse traces after the response is sent (serverless-friendly)
   217→    after(async () => {
   218→      await langfuseSpanProcessor.forceFlush();
   219→    });
   220→
   221→    // Return agent UI stream response with createAgentUIStreamResponse
   222→    return await createAgentUIStreamResponse({
   223→      agent: mediaAgent,
   224→      uiMessages: validatedMessages,
   225→      options: agentOptions,
   226→      // Use continuation message ID for multi-step tool execution (upsert pattern)
   227→      // This ensures client receives consistent IDs across all steps
   228→      generateMessageId: () => continuationMessageId || crypto.randomUUID(),
   229→      onError: (error) => {
   230→        // Enhanced error logging with type checking
   231→        if (error instanceof Error) {
   232→          logger.error(
   233→            `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${requestId}, stack=${error.stack}`,
   234→          );
   235→        } else {
   236→          logger.error(
   237→            `Unknown stream error: error=${JSON.stringify(error)}, requestId=${requestId}`,
   238→          );
   239→        }
   240→
   241→        // Return context-aware error messages
   242→        const errorMessage = error instanceof Error ? error.message : "";
   243→
   244→        if (errorMessage.includes("rate limit")) {
   245→          return "I'm experiencing high demand right now. Please try again in a moment.";
   246→        }
   247→
   248→        if (errorMessage.includes("timeout")) {
   249→          return "The request took too long. Please try a simpler question.";
   250→        }
   251→
   252→        if (errorMessage.includes("context length")) {
   253→          return "The conversation is too long. Please start a new chat.";
   254→        }
   255→
   256→        const messageToUser =
   257→          "Sorry, I am not able to respond right now. Please try again later.";
   258→
   259→        updateAgentObservation({
   260→          output: messageToUser,
   261→          level: "ERROR",
   262→        });
   263→        updateAgentTrace({
   264→          output: messageToUser,
   265→        });
   266→
   267→        endActiveSpan();
   268→        return messageToUser;
   269→      },
   270→      onFinish: async ({ responseMessage }) => {
   271→        // Update Langfuse trace with output
   272→        const outputText = responseMessage
   273→          ? extractTextFromUiMessage(responseMessage)
   274→          : undefined;
   275→
   276→        const outputForTrace =
   277→          outputText ??
   278→          (responseMessage
   279→            ? `[assistant] ${summarizeParts(responseMessage.parts)}`
   280→            : undefined);
   281→
   282→        updateAgentObservation({
   283→          output: outputForTrace,
   284→        });
   285→
   286→        updateAgentTrace({
   287→          output: outputForTrace,
   288→        });
   289→
   290→        endActiveSpan();
   291→
   292→        // Save assistant response message to database
   293→        // Upsert will update if already exists (from previous tool-only saves)
   294→        if (responseMessage && responseMessage.parts.length > 0) {
   295→          // ID priority: responseMessage.id > continuationMessageId > new UUID
   296→          // This ensures multi-step tool executions share the same message ID
   297→          const messageId =
   298→            responseMessage.id || continuationMessageId || crypto.randomUUID();
   299→
   300→          const messageToSave: UIMessage = {
   301→            ...responseMessage,
   302→            id: messageId,
   303→          };
   304→
   305→          try {
   306→            await saveChatMessage({
   307→              message: messageToSave,
   308→              chatId: chat.id,
   309→              userId,
   310→            });
   311→            logger.info(
   312→              `Assistant message saved: ${messageToSave.id} (${messageToSave.parts.length} parts)`,
   313→            );
   314→          } catch (saveError) {
   315→            logger.error(
   316→              `Failed to save assistant message: ${saveError instanceof Error ? saveError.message : String(saveError)}`,
   317→            );
   318→          }
   319→        } else if (responseMessage && responseMessage.parts.length === 0) {
   320→          logger.warn(
   321→            `Skipping save of assistant message ${responseMessage.id || "unknown"} - 0 parts (intermediate state)`,
   322→          );
   323→        }
   324→      },
   325→    });
   326→  } catch (error) {
   327→    // Enhanced pre-stream error logging
   328→    const errorMessage =
   329→      error instanceof Error ? error.message : "Unknown error";
   330→    const stack = error instanceof Error ? error.stack : "no stack";
   331→    logger.error(
   332→      `Error in POST request (before streaming): error=${errorMessage}, requestId=${requestId}, stack=${stack}`,
   333→    );
   334→
   335→    // Update Langfuse trace with error
   336→    updateAgentObservation({
   337→      output: errorMessage,
   338→      level: "ERROR",
   339→    });
   340→
   341→    updateAgentTrace({
   342→      output: errorMessage,
   343→    });
   344→
   345→    endActiveSpan();
   346→
   347→    try {
   348→      const textId = crypto.randomUUID();
   349→
   350→      const stream = createUIMessageStream<UIMessage>({
   351→        originalMessages: [message],
   352→        execute: ({ writer }) => {
   353→          writer.write({ type: "text-start", id: textId });
   354→          writer.write({
   355→            type: "text-delta",
   356→            id: textId,
   357→            delta:
   358→              "Sorry, I am not able to respond right now. Please try again later.",
   359→          });
   360→          writer.write({ type: "text-end", id: textId });
   361→        },
   362→      });
   363→
   364→      return createUIMessageStreamResponse({ stream });
   365→    } catch (streamError) {
   366→      const streamErrorMsg =
   367→        streamError instanceof Error
   368→          ? streamError.message
   369→          : String(streamError);
   370→      logger.error(
   371→        `Failed to create error stream: error=${streamErrorMsg}, requestId=${requestId}`,
   372→      );
   373→
   374→      // Fallback to plain text response if stream creation fails
   375→      return new Response(
   376→        JSON.stringify({
   377→          error:
   378→            "An error occurred while processing your request. Please try again.",
   379→        }),
   380→        {
   381→          status: 500,
   382→          headers: { "Content-Type": "application/json" },
   383→        },
   384→      );
   385→    }
   386→  }
   387→};
   388→
   389→// Wrap handler with Langfuse observe for automatic tracing
   390→// endOnExit: false keeps the observation open during streaming
   391→export const POST = observe(handler, {
   392→  name: "handle-agent-chat",
   393→  endOnExit: false,
   394→});
   395→

