     1→import logger from "@/utils/logger";
     2→
     3→/**
     4→ * Maps error messages to user-friendly messages
     5→ */
     6→export function getErrorMessage(error: unknown): string {
     7→  const errorMessage = error instanceof Error ? error.message : "";
     8→
     9→  if (errorMessage.includes("rate limit")) {
    10→    return "I'm experiencing high demand right now. Please try again in a moment.";
    11→  }
    12→
    13→  if (errorMessage.includes("timeout")) {
    14→    return "The request took too long. Please try a simpler question.";
    15→  }
    16→
    17→  if (errorMessage.includes("context length")) {
    18→    return "The conversation is too long. Please start a new chat.";
    19→  }
    20→
    21→  return "Sorry, I am not able to respond right now. Please try again later.";
    22→}
    23→
    24→/**
    25→ * Logs agent errors with structured context
    26→ */
    27→export function logAgentError(
    28→  error: unknown,
    29→  context: { requestId: string; [key: string]: unknown },
    30→): void {
    31→  if (error instanceof Error) {
    32→    logger.error(
    33→      `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${context.requestId}, stack=${error.stack}`,
    34→    );
    35→  } else {
    36→    logger.error(
    37→      `Unknown stream error: error=${JSON.stringify(error)}, requestId=${context.requestId}`,
    38→    );
    39→  }
    40→}
    41→
    42→/**
    43→ * Factory for creating onError callback for agent streams
    44→ */
    45→export function createStreamErrorHandler(context: { requestId: string }) {
    46→  return (error: unknown): string => {
    47→    logAgentError(error, context);
    48→    return getErrorMessage(error);
    49→  };
    50→}
