     1→import { updateActiveObservation, updateActiveTrace } from "@langfuse/tracing";
     2→import { trace } from "@opentelemetry/api";
     3→
     4→// Re-export observe using export from
     5→export { observe } from "@langfuse/tracing";
     6→
     7→type TraceParams = Parameters<typeof updateActiveTrace>[0];
     8→type ObservationParams = Parameters<typeof updateActiveObservation>[0];
     9→
    10→/**
    11→ * Wrapper for Langfuse trace updates with consistent error handling
    12→ */
    13→export function updateAgentTrace(params: TraceParams): void {
    14→  updateActiveTrace(params);
    15→}
    16→
    17→/**
    18→ * Wrapper for Langfuse observation updates with consistent error handling
    19→ */
    20→export function updateAgentObservation(params: ObservationParams): void {
    21→  updateActiveObservation(params);
    22→}
    23→
    24→/**
    25→ * Helper to end the active OpenTelemetry span
    26→ */
    27→export function endActiveSpan(): void {
    28→  trace.getActiveSpan()?.end();
    29→}
    30→

