   260→          const isToolPart =
   261→            typeof part === "object" &&
   262→            part !== null &&
   263→            "type" in part &&
   264→            typeof part.type === "string" &&
   265→            part.type.startsWith("tool-") &&
   266→            "state" in part &&
   267→            part.state === "output-available" &&
   268→            "output" in part &&
   269→            part.output !== undefined &&
   270→            "toolCallId" in part &&
