   350→
   351→            // Extend polling data with S3 URL
   352→            const extendedVideoReplicatePollingData = {
   353→              ...videoReplicatePollingData,
   354→              s3Url,
   355→            };
   356→
   357→            const baseMetadata: Record<string, unknown> = {
   358→              source: "agent-chat",
   359→              mediaType: "video",
   360→              toolCallId,
   361→              chatId: activeChatIdRef.current,
   362→              projectId,
   363→              createdAt: new Date().toISOString(),
   364→              model: toolNameCamelCase || "video-upscaler",
