   387→            // Generate S3 key/URL upfront using predictionId
   388→            const s3Key = generateS3KeyFromPredictionId(
   389→              imagePollingData.predictionId,
   390→              "image-generation", // Default toolName, can be enhanced later
   391→              0, // index for single image
