    10→import { Agent, AgentCallParameters, AgentStreamParameters } from './agent';
    11→import { ToolLoopAgentOnStepFinishCallback } from './tool-loop-agent-on-step-finish-callback';
    12→import { ToolLoopAgentSettings } from './tool-loop-agent-settings';
    13→
    14→/**
    15→ * A tool loop agent is an agent that runs tools in a loop. In each step,
    16→ * it calls the LLM, and if there are tool calls, it executes the tools
    17→ * and calls the LLM again in a new step with the tool results.
    18→ *
    19→ * The loop continues until:
    20→ * - A finish reasoning other than tool-calls is returned, or
    21→ * - A tool that is invoked does not have an execute function, or
    22→ * - A tool call needs approval, or
    23→ * - A stop condition is met (default stop condition is stepCountIs(20))
    24→ */
    25→export class ToolLoopAgent<
    26→  CALL_OPTIONS = never,
    27→  TOOLS extends ToolSet = {},
    28→  OUTPUT extends Output = never,
    29→> implements Agent<CALL_OPTIONS, TOOLS, OUTPUT>
    30→{
    31→  readonly version = 'agent-v1';
    32→
    33→  private readonly settings: ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>;
    34→
    35→  constructor(settings: ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>) {
    36→    this.settings = settings;
    37→  }
    38→
    39→  /**
    40→   * The id of the agent.
    41→   */
    42→  get id(): string | undefined {
    43→    return this.settings.id;
    44→  }
    45→
    46→  /**
    47→   * The tools that the agent can use.
    48→   */
    49→  get tools(): TOOLS {
    50→    return this.settings.tools as TOOLS;
    51→  }
    52→
    53→  private async prepareCall(options: {
    54→    prompt?: string | Array<import('@ai-sdk/provider-utils').ModelMessage>;
    55→    messages?: Array<import('@ai-sdk/provider-utils').ModelMessage>;
    56→    options?: CALL_OPTIONS;
    57→  }): Promise<
    58→    Omit<
    59→      ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>,
    60→      'prepareCall' | 'instructions' | 'onStepFinish'
    61→    > &
    62→      Prompt
    63→  > {
    64→    const { onStepFinish: _settingsOnStepFinish, ...settingsWithoutCallback } =
    65→      this.settings;
    66→
    67→    const baseCallArgs = {
    68→      ...settingsWithoutCallback,
    69→      stopWhen: this.settings.stopWhen ?? stepCountIs(20),
    70→      ...options,
    71→    };
    72→
    73→    const preparedCallArgs =
    74→      (await this.settings.prepareCall?.(
    75→        baseCallArgs as Parameters<
    76→          NonNullable<
    77→            ToolLoopAgentSettings<CALL_OPTIONS, TOOLS, OUTPUT>['prepareCall']
    78→          >
    79→        >[0],
    80→      )) ?? baseCallArgs;
    81→
    82→    const { instructions, messages, prompt, ...callArgs } = preparedCallArgs;
    83→
    84→    return {
    85→      ...callArgs,
    86→
    87→      // restore prompt types
    88→      ...({ system: instructions, messages, prompt } as Prompt),
    89→    };
    90→  }
    91→
    92→  private mergeOnStepFinishCallbacks(
    93→    methodCallback: ToolLoopAgentOnStepFinishCallback<TOOLS> | undefined,
    94→  ): ToolLoopAgentOnStepFinishCallback<TOOLS> | undefined {
    95→    const constructorCallback = this.settings.onStepFinish;
    96→
    97→    if (methodCallback && constructorCallback) {
    98→      return async (stepResult: StepResult<TOOLS>) => {
    99→        await constructorCallback(stepResult);
   100→        await methodCallback(stepResult);
   101→      };
   102→    }
   103→
   104→    return methodCallback ?? constructorCallback;
   105→  }
   106→
   107→  /**
   108→   * Generates an output from the agent (non-streaming).
   109→   */
   110→  async generate({
   111→    abortSignal,
   112→    timeout,
   113→    onStepFinish,
   114→    ...options
   115→  }: AgentCallParameters<CALL_OPTIONS, TOOLS>): Promise<
   116→    GenerateTextResult<TOOLS, OUTPUT>
   117→  > {
   118→    return generateText({
   119→      ...(await this.prepareCall(options)),
   120→      abortSignal,
   121→      timeout,
   122→      onStepFinish: this.mergeOnStepFinishCallbacks(onStepFinish),
   123→    });
   124→  }
   125→
   126→  /**
   127→   * Streams an output from the agent (streaming).
   128→   */
   129→  async stream({
   130→    abortSignal,
   131→    timeout,
   132→    experimental_transform,
   133→    onStepFinish,
   134→    ...options
   135→  }: AgentStreamParameters<CALL_OPTIONS, TOOLS>): Promise<
   136→    StreamTextResult<TOOLS, OUTPUT>
   137→  > {
   138→    return streamText({
   139→      ...(await this.prepareCall(options)),
   140→      abortSignal,
   141→      timeout,
   142→      experimental_transform,
   143→      onStepFinish: this.mergeOnStepFinishCallbacks(onStepFinish),
   144→    });
   145→  }
   146→}
