    11→
    12→/**
    13→ * Runs the agent and returns a response object with a UI message stream.
    14→ *
    15→ * @param agent - The agent to run.
    16→ * @param uiMessages - The input UI messages.
    17→ * @param abortSignal - Abort signal. Optional.
    18→ * @param timeout - Timeout in milliseconds. Optional.
    19→ * @param options - The options for the agent. Optional.
    20→ * @param experimental_transform - Stream transformations. Optional.
    21→ * @param onStepFinish - Callback that is called when each step is finished. Optional.
    22→ * @param headers - Additional headers for the response. Optional.
    23→ * @param status - The status code for the response. Optional.
    24→ * @param statusText - The status text for the response. Optional.
    25→ * @param consumeSseStream - Whether to consume the SSE stream. Optional.
    26→ *
    27→ * @returns The response object.
    28→ */
    29→export async function createAgentUIStreamResponse<
    30→  CALL_OPTIONS = never,
    31→  TOOLS extends ToolSet = {},
    32→  OUTPUT extends Output = never,
    33→  MESSAGE_METADATA = unknown,
    34→>({
    35→  headers,
    36→  status,
    37→  statusText,
    38→  consumeSseStream,
    39→  ...options
    40→}: {
    41→  agent: Agent<CALL_OPTIONS, TOOLS, OUTPUT>;
    42→  uiMessages: unknown[];
    43→  abortSignal?: AbortSignal;
    44→  timeout?: TimeoutConfiguration;
    45→  options?: CALL_OPTIONS;
    46→  experimental_transform?:
    47→    | StreamTextTransform<TOOLS>
    48→    | Array<StreamTextTransform<TOOLS>>;
    49→  onStepFinish?: ToolLoopAgentOnStepFinishCallback<TOOLS>;
    50→} & UIMessageStreamResponseInit &
    51→  UIMessageStreamOptions<
    52→    UIMessage<MESSAGE_METADATA, never, InferUITools<TOOLS>>
    53→  >): Promise<Response> {
    54→  return createUIMessageStreamResponse({
    55→    headers,
    56→    status,
    57→    statusText,
    58→    consumeSseStream,
    59→    stream: await createAgentUIStream(options),
    60→  });
    61→}
