     3→/**
     4→ * Media type classification
     5→ */
     6→export type MediaType = "image" | "video" | "audio";
     7→
     8→/**
     9→ * Extracted media information from tool output
    10→ */
    11→export type MediaInfo = {
    12→  urls: string[];
    13→  type: MediaType;
    14→};
    15→
    16→/**
    17→ * Type guard to check if value is a record
    18→ */
    19→const isRecord = (v: unknown): v is Record<string, unknown> =>
    20→  typeof v === "object" && v !== null;
    21→
    22→/**
    23→ * Detect media type from MIME type string
    24→ */
    25→const detectMediaTypeFromMime = (mimeType: string): MediaType => {
    26→  if (mimeType.startsWith("video/")) return "video";
    27→  if (mimeType.startsWith("audio/")) return "audio";
    28→  if (mimeType.startsWith("image/")) return "image";
    29→  return "image"; // Default fallback
    30→};
    31→
    32→/**
    33→ * Detect media type from URL by analyzing file extension
    34→ */
    35→export const detectMediaTypeFromUrl = (url: string): MediaType => {
    36→  const urlWithoutQuery = url.split("?")[0];
    37→  const mimeType = detectContentType(urlWithoutQuery);
    38→  return detectMediaTypeFromMime(mimeType);
    39→};
    40→
    41→/**
    42→ * Extract media URLs from tool output result
    43→ *
    44→ * Supports multiple formats:
    45→ * - { src: "url" } or { output: "url" }
    46→ * - { src: ["url1", "url2"] } or { output: ["url1", "url2"] }
    47→ *
    48→ * @param result - Tool output result (unknown type)
    49→ * @returns Media info with URLs and detected type, or null if no media found
    50→ */
    51→export const extractMediaUrls = (result: unknown): MediaInfo | null => {
    52→  if (!isRecord(result)) return null;
    53→
    54→  const src = result.src || result.output;
    55→  let urls: string[] = [];
    56→
    57→  if (Array.isArray(src)) {
    58→    urls = src.filter((x): x is string => typeof x === "string");
    59→  } else if (typeof src === "string") {
    60→    urls = [src];
    61→  }
    62→
    63→  if (urls.length === 0) return null;
    64→
    65→  // Detect type from first URL using content type detection
    66→  const firstUrl = urls[0];
    67→  const detectedType = detectMediaTypeFromUrl(firstUrl);
    68→
    69→  return { urls, type: detectedType };
    70→};
    71→
    72→/**
    73→ * Extract video polling data from tool output result
    74→ *
    75→ * Supports formats:
    76→ * - { output: { predictionId: "...", requestLink: "..." } }
    77→ * - { output: { output: { predictionId: "...", requestLink: "..." } } }
    78→ *
    79→ * @param result - Tool output result (unknown type)
    80→ * @returns Polling data with predictionId and requestLink, or null if not found
    81→ */
    82→export const extractVideoPollingData = (
    83→  result: unknown,
    84→): { predictionId: string; requestLink: string; provider?: string } | null => {
    85→  if (!isRecord(result)) return null;
    86→
    87→  // Try direct output first
    88→  const output = result.output;
    89→  if (isRecord(output)) {
    90→    // Check if output has predictionId and requestLink directly
    91→    if (
    92→      typeof output.predictionId === "string" &&
    93→      typeof output.requestLink === "string"
    94→    ) {
    95→      // FAL tools return a requestLink for polling. Mark provider as fal-ai
    96→      return {
    97→        predictionId: output.predictionId,
    98→        requestLink: output.requestLink,
    99→        provider: "fal-ai",
   100→      };
   101→    }
   102→
   103→    // Check if output has nested output
   104→    const nestedOutput = output.output;
   105→    if (
   106→      isRecord(nestedOutput) &&
   107→      typeof nestedOutput.predictionId === "string" &&
   108→      typeof nestedOutput.requestLink === "string"
   109→    ) {
   110→      // FAL tools return a requestLink for polling. Mark provider as fal-ai
   111→      return {
   112→        predictionId: nestedOutput.predictionId,
   113→        requestLink: nestedOutput.requestLink,
   114→        provider: "fal-ai",
   115→      };
   116→    }
   117→  }
   118→
   119→  return null;
   120→};
