     1→import { executeTool, ModelMessage } from '@ai-sdk/provider-utils';
     2→import { Tracer } from '@opentelemetry/api';
     3→import { assembleOperationName } from '../telemetry/assemble-operation-name';
     4→import { recordErrorOnSpan, recordSpan } from '../telemetry/record-span';
     5→import { selectTelemetryAttributes } from '../telemetry/select-telemetry-attributes';
     6→import { TelemetrySettings } from '../telemetry/telemetry-settings';
     7→import { TypedToolCall } from './tool-call';
     8→import { ToolOutput } from './tool-output';
     9→import { ToolSet } from './tool-set';
    10→import { TypedToolResult } from './tool-result';
    11→import { TypedToolError } from './tool-error';
    12→
    13→export async function executeToolCall<TOOLS extends ToolSet>({
    14→  toolCall,
    15→  tools,
    16→  tracer,
    17→  telemetry,
    18→  messages,
    19→  abortSignal,
    20→  experimental_context,
    21→  onPreliminaryToolResult,
    22→}: {
    23→  toolCall: TypedToolCall<TOOLS>;
    24→  tools: TOOLS | undefined;
    25→  tracer: Tracer;
    26→  telemetry: TelemetrySettings | undefined;
    27→  messages: ModelMessage[];
    28→  abortSignal: AbortSignal | undefined;
    29→  experimental_context: unknown;
    30→  onPreliminaryToolResult?: (result: TypedToolResult<TOOLS>) => void;
    31→}): Promise<ToolOutput<TOOLS> | undefined> {
    32→  const { toolName, toolCallId, input } = toolCall;
    33→  const tool = tools?.[toolName];
    34→
    35→  if (tool?.execute == null) {
    36→    return undefined;
    37→  }
    38→
    39→  return recordSpan({
    40→    name: 'ai.toolCall',
    41→    attributes: selectTelemetryAttributes({
    42→      telemetry,
    43→      attributes: {
    44→        ...assembleOperationName({
    45→          operationId: 'ai.toolCall',
    46→          telemetry,
    47→        }),
    48→        'ai.toolCall.name': toolName,
    49→        'ai.toolCall.id': toolCallId,
    50→        'ai.toolCall.args': {
    51→          output: () => JSON.stringify(input),
    52→        },
    53→      },
    54→    }),
    55→    tracer,
    56→    fn: async span => {
    57→      let output: unknown;
    58→
    59→      try {
    60→        const stream = executeTool({
    61→          execute: tool.execute!.bind(tool),
    62→          input,
    63→          options: {
    64→            toolCallId,
    65→            messages,
    66→            abortSignal,
    67→            experimental_context,
    68→          },
    69→        });
    70→
    71→        for await (const part of stream) {
    72→          if (part.type === 'preliminary') {
    73→            onPreliminaryToolResult?.({
    74→              ...toolCall,
    75→              type: 'tool-result',
    76→              output: part.output,
    77→              preliminary: true,
    78→            });
    79→          } else {
    80→            output = part.output;
    81→          }
    82→        }
    83→      } catch (error) {
    84→        recordErrorOnSpan(span, error);
    85→        return {
    86→          type: 'tool-error',
    87→          toolCallId,
    88→          toolName,
    89→          input,
    90→          error,
    91→          dynamic: tool.type === 'dynamic',
    92→          ...(toolCall.providerMetadata != null
    93→            ? { providerMetadata: toolCall.providerMetadata }
    94→            : {}),
    95→        } as TypedToolError<TOOLS>;
    96→      }
    97→
    98→      try {
    99→        span.setAttributes(
   100→          await selectTelemetryAttributes({
   101→            telemetry,
   102→            attributes: {
   103→              'ai.toolCall.result': {
   104→                output: () => JSON.stringify(output),
   105→              },
   106→            },
   107→          }),
   108→        );
   109→      } catch (ignored) {
   110→        // JSON stringify might fail if the result is not serializable,
   111→        // in which case we just ignore it. In the future we might want to
   112→        // add an optional serialize method to the tool interface and warn
   113→        // if the result is not serializable.
   114→      }
   115→
   116→      return {
   117→        type: 'tool-result',
   118→        toolCallId,
   119→        toolName,
   120→        input,
   121→        output,
   122→        dynamic: tool.type === 'dynamic',
   123→        ...(toolCall.providerMetadata != null
   124→          ? { providerMetadata: toolCall.providerMetadata }
   125→          : {}),
   126→      } as TypedToolResult<TOOLS>;
   127→    },
   128→  });
   129→}
