     1→import { isAsyncIterable } from '../is-async-iterable';
     2→import { ToolExecutionOptions, ToolExecuteFunction } from './tool';
     3→
     4→export async function* executeTool<INPUT, OUTPUT>({
     5→  execute,
     6→  input,
     7→  options,
     8→}: {
     9→  execute: ToolExecuteFunction<INPUT, OUTPUT>;
    10→  input: INPUT;
    11→  options: ToolExecutionOptions;
    12→}): AsyncGenerator<
    13→  { type: 'preliminary'; output: OUTPUT } | { type: 'final'; output: OUTPUT }
    14→> {
    15→  const result = execute(input, options);
    16→
    17→  if (isAsyncIterable(result)) {
    18→    let lastOutput: OUTPUT | undefined;
    19→    for await (const output of result) {
    20→      lastOutput = output;
    21→      yield { type: 'preliminary', output };
    22→    }
    23→    yield { type: 'final', output: lastOutput! };
    24→  } else {
    25→    yield { type: 'final', output: await result };
    26→  }
    27→}
